4299       if (Pred == ICmpInst::ICMP_SGT && C.isAllOnes())
4300         return new ICmpInst(ICmpInst::ICMP_SGE, II->getArgOperand(0),
4301                             II->getArgOperand(1));
4302     }
4303     break;
