4305     if (!II->hasOneUse())
4306       return nullptr;
4307 
4308     Value *X = II->getArgOperand(0);
4309     bool IsIntMinPoison =
4310         cast<ConstantInt>(II->getArgOperand(1))->getValue().isOne();
4311 
4312     // If C >= 0:
4313     // abs(X) u> C --> X + C u> 2 * C
4314     if (Pred == CmpInst::ICMP_UGT && C.isNonNegative()) {
4315       return new ICmpInst(ICmpInst::ICMP_UGT,
4316                           Builder.CreateAdd(X, ConstantInt::get(Ty, C)),
4317                           ConstantInt::get(Ty, 2 * C));
4318     }
4319 
4320     // If abs(INT_MIN) is poison and C >= 1:
4321     // abs(X) u< C --> X + (C - 1) u<= 2 * (C - 1)
4322     if (IsIntMinPoison && Pred == CmpInst::ICMP_ULT && C.sge(1)) {
4323       return new ICmpInst(ICmpInst::ICMP_ULE,
4324                           Builder.CreateAdd(X, ConstantInt::get(Ty, C - 1)),
4325                           ConstantInt::get(Ty, 2 * (C - 1)));
4326     }
4327 
4328     break;
4329   }
4330   default:
4331     break;
4332   }
4333 
4334   return nullptr;
4335 }
