4368 Instruction *InstCombinerImpl::foldSelectICmp(CmpPredicate Pred, SelectInst *SI,
4369                                               Value *RHS, const ICmpInst &I) {
4370   // Try to fold the comparison into the select arms, which will cause the
4371   // select to be converted into a logical and/or.
4372   auto SimplifyOp = [&](Value *Op, bool SelectCondIsTrue) -> Value * {
4373     if (Value *Res = simplifyICmpInst(Pred, Op, RHS, SQ))
4374       return Res;
4375     if (std::optional<bool> Impl = isImpliedCondition(
4376             SI->getCondition(), Pred, Op, RHS, DL, SelectCondIsTrue))
4377       return ConstantInt::get(I.getType(), *Impl);
4378     return nullptr;
4379   };
4380 
4381   ConstantInt *CI = nullptr;
4382   Value *Op1 = SimplifyOp(SI->getOperand(1), true);
4383   if (Op1)
4384     CI = dyn_cast<ConstantInt>(Op1);
4385 
4386   Value *Op2 = SimplifyOp(SI->getOperand(2), false);
4387   if (Op2)
4388     CI = dyn_cast<ConstantInt>(Op2);
4389 
4390   auto Simplifies = [&](Value *Op, unsigned Idx) {
4391     // A comparison of ucmp/scmp with a constant will fold into an icmp.
4392     const APInt *Dummy;
4393     return Op ||
4394            (isa<CmpIntrinsic>(SI->getOperand(Idx)) &&
4395             SI->getOperand(Idx)->hasOneUse() && match(RHS, m_APInt(Dummy)));
4396   };
4397 
4398   // We only want to perform this transformation if it will not lead to
4399   // additional code. This is true if either both sides of the select
4400   // fold to a constant (in which case the icmp is replaced with a select
4401   // which will usually simplify) or this is the only user of the
4402   // select (in which case we are trading a select+icmp for a simpler
4403   // select+icmp) or all uses of the select can be replaced based on
4404   // dominance information ("Global cases").
4405   bool Transform = false;
4406   if (Op1 && Op2)
4407     Transform = true;
4408   else if (Simplifies(Op1, 1) || Simplifies(Op2, 2)) {
4409     // Local case
4410     if (SI->hasOneUse())
4411       Transform = true;
4412     // Global cases
4413     else if (CI && !CI->isZero())
4414       // When Op1 is constant try replacing select with second operand.
4415       // Otherwise Op2 is constant and try replacing select with first
4416       // operand.
4417       Transform = replacedSelectWithOperand(SI, &I, Op1 ? 2 : 1);
4418   }
4419   if (Transform) {
4420     if (!Op1)
4421       Op1 = Builder.CreateICmp(Pred, SI->getOperand(1), RHS, I.getName());
4422     if (!Op2)
4423       Op2 = Builder.CreateICmp(Pred, SI->getOperand(2), RHS, I.getName());
4424     return SelectInst::Create(SI->getOperand(0), Op1, Op2);
4425   }
4426 
4427   return nullptr;
4428 }
