4430 // Returns whether V is a Mask ((X + 1) & X == 0) or ~Mask (-Pow2OrZero)
4431 static bool isMaskOrZero(const Value *V, bool Not, const SimplifyQuery &Q,
4432                          unsigned Depth = 0) {
4433   if (Not ? match(V, m_NegatedPower2OrZero()) : match(V, m_LowBitMaskOrZero()))
4434     return true;
4435   if (V->getType()->getScalarSizeInBits() == 1)
4436     return true;
4437   if (Depth++ >= MaxAnalysisRecursionDepth)
4438     return false;
4439   Value *X;
4440   const Instruction *I = dyn_cast<Instruction>(V);
4441   if (!I)
4442     return false;
4443   switch (I->getOpcode()) {
4444   case Instruction::ZExt:
4445     // ZExt(Mask) is a Mask.
4446     return !Not && isMaskOrZero(I->getOperand(0), Not, Q, Depth);
4447   case Instruction::SExt:
4448     // SExt(Mask) is a Mask.
4449     // SExt(~Mask) is a ~Mask.
4450     return isMaskOrZero(I->getOperand(0), Not, Q, Depth);
